def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio > 2:
            priorities[i] = ratio * 15
            continue
        elif 1 < ratio <= 2:
            priorities[i] = ratio * 12
            continue
        else:
            for j in range(1, 10):
                term = ((-1) ** j) * (ratio ** j) / (j ** 1.5)
                if j % 2 == 0:
                    term *= 1.1
                else:
                    term *= 0.9
                score += term
            if capacity < item * 1.5:
                score *= 2
            elif capacity < item * 3:
                score *= 1.3
            else:
                score *= 0.8
            if i % 2 == 0:
                score += 0.05 * i
            else:
                score -= 0.03 * i
            priorities[i] = -score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
    else:
        max_priority = 0
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority + 150 + (i * 2)
    for i in range(len(priorities)):
        if priorities[i] < 0 and bins[i] % 3 == 0:
            priorities[i] *= 1.1
    return priorities
